    private func buildURLRequest(
        url: String,
        method: HTTPMethod,
        bodyData: Data?,
        configuration: RequestConfiguration
    ) throws -> URLRequest {
        guard var urlComponents = URLComponents(string: url) else {
            throw NetworkError.invalidURL
        }
        
        // Add query parameters if any
        if let queryParams = configuration.queryParameters, !queryParams.isEmpty {
            urlComponents.queryItems = queryParams.map {
                URLQueryItem(name: $0.key, value: $0.value)
            }
        }
        
        guard let finalURL = urlComponents.url else {
            throw NetworkError.invalidURL
        }
        
        var request = URLRequest(url: finalURL)
        request.httpMethod = method.rawValue
        request.timeoutInterval = configuration.timeoutInterval
        request.cachePolicy = configuration.cachePolicy
        
        // Apply headers
        for (key, value) in configuration.headers {
            request.setValue(value, forHTTPHeaderField: key)
        }
        
        // Set body data
        if let bodyData = bodyData {
            request.httpBody = bodyData
        }
        
        return request
    }
    
    /// Select the appropriate URLSession based on the target URL
    private func selectSession(for url: String) -> URLSession {
        let localPatterns = [
            "http://192.168.",
            "https://192.168.",
            "http://10.",
            "https://10.",
            "http://172.1",
            "https://172.1",
            "http://172.2",
            "https://172.2",
            "http://172.3",
            "https://172.3",
            "http://localhost",
            "https://localhost",
            "http://127.0.0.1",
            "https://127.0.0.1"
        ]
        
        let isLocal = localPatterns.contains { url.hasPrefix($0) }
        return isLocal ? insecureSession : secureSession
    }
