// MARK: - Example Models

/// Represents an IoT device on the local network
struct IoTDevice: Codable {
    let id: String
    let name: String
    let type: String
    let firmwareVersion: String?
    let status: DeviceStatus
    
    enum DeviceStatus: String, Codable {
        case online
        case offline
        case updating
        case error
    }
}

/// Represents a device command
struct DeviceCommand: Codable {
    let action: String
    let parameters: [String: String]?
}

/// Represents a device response
struct DeviceResponse: Codable {
    let success: Bool
    let message: String?
    let data: [String: String]?
}

/// Cloud API user model
struct User: Codable {
    let id: Int
    let email: String
    let name: String
}

/// Cloud API auth response
struct AuthResponse: Codable {
    let token: String
    let user: User
    let expiresAt: Date?
}

/// Cloud API generic list response
struct ListResponse<T: Codable>: Codable {
    let items: [T]
    let total: Int
    let page: Int
    let pageSize: Int
}

/// Cloud-registered device info
struct CloudDevice: Codable {
    let id: String
    let name: String
    let localIP: String?
    let lastSeen: Date?
    let ownerId: Int
}

// MARK: - IoT Device Manager

class IoTDeviceManager {
    
    private let client = HTTPClient.shared
    
    /// Discover devices on the local network
    func discoverDevices(subnet: String = "192.168.1") async -> [IoTDevice] {
        let ips = await client.scanSubnet(subnet: subnet, port: 80)
        var devices: [IoTDevice] = []
        
        for ip in ips {
            do {
                let response = try await client.deviceGet(
                    deviceIP: ip,
                    path: "/api/info",
                    responseType: IoTDevice.self
                )
                devices.append(response.data)
            } catch {
                print("Device at \(ip) did not respond to info request: \(error.localizedDescription)")
            }
        }
        
        return devices
    }
    
    /// Send a command to a specific device
    func sendCommand(
        to deviceIP: String,
        port: Int = 80,
        command: DeviceCommand
    ) async throws -> DeviceResponse {
        let response = try await client.devicePost(
            deviceIP: deviceIP,
            port: port,
            path: "/api/command",
            body: command,
            responseType: DeviceResponse.self
        )
        return response.data
    }
    
    /// Get device status
    func getDeviceStatus(ip: String, port: Int = 80) async throws -> IoTDevice {
        let response = try await client.deviceGet(
            deviceIP: ip,
            port: port,
            path: "/api/status",
            responseType: IoTDevice.self
        )
        return response.data
    }
    
    /// Update device firmware via raw binary upload
    func updateFirmware(
        deviceIP: String,
        port: Int = 80,
        firmwareData: Data
    ) async throws -> DeviceResponse {
        let rawResponse = try await client.deviceSendRaw(
            deviceIP: deviceIP,
            port: port,
            path: "/api/firmware/update",
            rawBody: firmwareData,
            contentType: "application/octet-stream"
        )
        
        let decoder = JSONDecoder()
        let decoded = try decoder.decode(DeviceResponse.self, from: rawResponse.rawData)
        return decoded
    }
    
    /// Toggle a device (e.g., smart switch)
    func toggleDevice(ip: String, port: Int = 80, on: Bool) async throws -> DeviceResponse {
        let command = DeviceCommand(
            action: on ? "turn_on" : "turn_off",
            parameters: nil
        )
        return try await sendCommand(to: ip, port: port, command: command)
    }
    
    /// Set device property (e.g., brightness, temperature)
    func setProperty(
        ip: String,
        port: Int = 80,
        property: String,
        value: String
    ) async throws -> DeviceResponse {
        let command = DeviceCommand(
            action: "set_property",
            parameters: [property: value]
        )
        return try await sendCommand(to: ip, port: port, command: command)
    }
}

// MARK: - Cloud API Manager

class CloudAPIManager {
    
    private let client = HTTPClient.shared
    
    /// Authenticate with the cloud API
    func login(email: String, password: String) async throws -> AuthResponse {
        struct LoginRequest: Codable {
            let email: String
            let password: String
        }
        
        let response = try await client.cloudPost(
            path: "/v1/auth/login",
            body: LoginRequest(email: email, password: password),
            responseType: AuthResponse.self
        )
        
        // Store the auth token for subsequent requests
        client.authToken = response.data.token
        
        return response.data
    }
    
    /// Register a new device with the cloud
    func registerDevice(_ device: IoTDevice, localIP: String) async throws -> CloudDevice {
        struct RegisterRequest: Codable {
            let deviceId: String
            let name: String
            let type: String
            let localIP: String
        }
        
        let response = try await client.cloudPost(
            path: "/v1/devices",
            body: RegisterRequest(
                deviceId: device.id,
                name: device.name,
                type: device.type,
                localIP: localIP
            ),
            responseType: CloudDevice.self
        )
        return response.data
    }
    
    /// Get all registered devices from the cloud
    func getRegisteredDevices(page: Int = 1, pageSize: Int = 50) async throws -> ListResponse<CloudDevice> {
        let response = try await client.cloudGet(
            path: "/v1/devices",
            queryParameters: [
                "page": "\(page)",
                "page_size": "\(pageSize)"
            ],
            responseType: ListResponse<CloudDevice>.self
        )
        return response.data
    }
    
    /// Sync local device status to the cloud
    func syncDeviceStatus(deviceId: String, status: IoTDevice.DeviceStatus) async throws {
        struct StatusUpdate: Codable {
            let status: IoTDevice.DeviceStatus
        }
        
        _ = try await client.cloudPut(
            path: "/v1/devices/\(deviceId)/status",
            body: StatusUpdate(status: status),
            responseType: DeviceResponse.self
        )
    }
    
    /// Get user profile
    func getUserProfile() async throws -> User {
        let response = try await client.cloudGet(
            path: "/v1/user/profile",
            responseType: User.self
        )
        return response.data
    }
    
    /// Logout
    func logout() async throws {
        struct EmptyBody: Codable {}
        _ = try await client.cloudPost(
            path: "/v1/auth/logout",
            body: EmptyBody(),
            responseType: DeviceResponse.self
        )
        client.authToken = nil
    }
}

