// MARK: - Usage Example

func exampleUsage() async {
    let cloudManager = CloudAPIManager()
    let deviceManager = IoTDeviceManager()
    
    // --- Cloud API Usage ---
    do {
        // Login to cloud
        let auth = try await cloudManager.login(email: "user@example.com", password: "password123")
        print("Logged in as: \(auth.user.name)")
        
        // Get registered devices from cloud
        let cloudDevices = try await cloudManager.getRegisteredDevices()
        print("Found \(cloudDevices.total) registered devices")
        
    } catch let error as NetworkError {
        print("Cloud API error: \(error.localizedDescription)")
    } catch {
        print("Unexpected error: \(error)")
    }
    
    // --- Local IoT Device Usage ---
    do {
        // Discover devices on local network
        let localDevices = await deviceManager.discoverDevices(subnet: "192.168.1")
        print("Discovered \(localDevices.count) local devices")
        
        // Toggle a smart switch at a known IP
        let toggleResult = try await deviceManager.toggleDevice(ip: "192.168.1.100", on: true)
        print("Toggle result: \(toggleResult.message ?? "OK")")
        
        // Set brightness on a smart light
        let brightnessResult = try await deviceManager.setProperty(
            ip: "192.168.1.101",
            property: "brightness",
            value: "75"
        )
        print("Brightness set: \(brightnessResult.success)")
        
        // Get device status
        let status = try await deviceManager.getDeviceStatus(ip: "192.168.1.100")
        print("Device \(status.name) is \(status.status)")
        
        // Send raw HTTP request to a legacy device
        let client = HTTPClient.shared
        let legacyResponse = try await client.deviceSendRaw(
            deviceIP: "192.168.1.200",
            port: 8080,
            path: "/control?relay=1&state=on",
            contentType: "text/plain"
        )
        print("Legacy device response: \(String(data: legacyResponse.rawData, encoding: .utf8) ?? "N/A")")
        
    } catch let error as NetworkError {
        print("Device error: \(error.localizedDescription)")
    } catch {
        print("Unexpected error: \(error)")
    }
    
    // --- Direct HTTP Client Usage ---
    do {
        let client = HTTPClient.shared
        
        // Direct GET to a local HTTP device (insecure)
        let response = try await client.requestRaw(
            url: "http://192.168.1.50/api/sensor/temperature",
            method: .GET,
            body: nil,
            configuration: .localDevice
        )
        
        if let temp = String(data: response.rawData, encoding: .utf8) {
            print("Temperature reading: \(temp)")
        }
        
        // Direct GET to cloud HTTPS API (secure)
        struct SensorReading: Codable {
            let temperature: Double
            let humidity: Double
            let timestamp: Date
        }
        
        let cloudResponse = try await client.request(
            url: "https://api.example.com/v1/readings/latest",
            method: .GET,
            body: Optional<String>.none,
            configuration: .cloudAPI,
            responseType: [SensorReading].self
        )
        
        for reading in cloudResponse.data {
            print("Cloud reading: \(reading.temperature)°C, \(reading.humidity)%")
        }
        
    } catch {
        print("Error: \(error)")
    }
}